<?php session_start();if(!$_SESSION['id'])    die();require('../classes/mysql.class.php');$db = new MySQL();$id_notify = $db->SQLfix(($_GET['id_notify']));$t = explode('_', $id_notify);if($t[1]) {    if ($_GET['action'] == 'delete') {        $sql = 'DELETE FROM notifications_desactivees WHERE id_notification = "' . $t[1] . '" AND compte_principal="' . $_SESSION['compte_principal'] . '" ';        $db->Query($sql);    }    if ($_GET['action'] == 'insert') {        $sql = 'INSERT INTO notifications_desactivees (id_notification, compte_principal) VALUES ("' . $t[1] . '", "' . $_SESSION['compte_principal'] . '" ) ';        $db->Query($sql);    }}$db->Close();?>